use alloy::sol;

sol! {
    struct PoolKey {
        address currency0;
        address currency1;
        uint24 fee;
        int24 tickSpacing;
        address hooks;
    }

    /// Flat struct for ABI-encoding/decoding V4 pool identifiers passed as `pool_id: Bytes`.
    struct V4PoolId {
        address poolManager;
        address currency0;
        address currency1;
        uint24 fee;
        int24 tickSpacing;
        address hooks;
    }

    struct QuoterConstructorArgs {
        address poolManager;
        PoolKey key;
        address tokenIn;
        uint256 amountIn;
        uint256 protocolFeeBps;
    }

    /**
     * @notice Quotes output for Uniswap V4 pool (exact input single).
     * @dev Uses PoolManager.unlock() → unlockCallback() → swap() and reverts with amountOut.
     */
    #[sol(rpc, bytecode="")]
    contract UniswapV4QuoteSingle {
        error AmountOut(uint256 amountOut);
        error InsufficientLiquidity();
        /// Bubbles up from PoolManager when the pool has never been initialized.
        error PoolNotInitialized();

        constructor(address poolManager, PoolKey key, address tokenIn, uint256 amountIn, uint256 protocolFeeBps);
    }
}
